VALUES
  ('cpa-moex-00518', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司生產兩種主要產品K1和K2，兩產品相關資料如下： 產品 生產量 分離點後額外成本 銷售量 銷售價格 K1 12,500 $ 10,500 12,000 $45 K2 17,500 $480,000 15,000 $80 共同製程中的聯合成本總計$530,000，若甲公司採用固定毛利率淨變現價值法，則產品K2需 分攤多少聯合成本？', '["$341,100", "$248,000", "$223,800", "$192,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00519', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列是甲公司20X1年有關實際與預算的相關資料： 實際數目 靜態預算 銷售量 25,000 30,000 變動成本 $125,000 $180,000 固定成本 $48,000 $50,000 該公司每單位預算售價$50，實際售價$60，則營業利益的靜態預算差異與彈性預算差異各為何？', '["營業利益靜態預算差異：$220,000（不利）；營業利益彈性預算差異：$277,000（有利）", "營業利益靜態預算差異：$277,000（有利）；營業利益彈性預算差異：$57,000（有利）", "營業利益靜態預算差異：$57,000（有利）；營業利益彈性預算差異：$277,000（有利）", "營業利益靜態預算差異：$57,000（有利）；營業利益彈性預算差異：$220,000（不利）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00520', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '穩康公司產品單位成本資料如下： 直接材料$50，直接人工$40，變動製造費用$70，固定製造費用$80，變動銷售及管理費用$35， 固定銷售及管理費用$65，在全部成本法（fullcosting）及變動成本法（variablecosting）下存 貨的單位成本分別為何？', '["全部成本法下存貨的單位成本$240；變動成本法下存貨的單位成本$160", "全部成本法下存貨的單位成本$320；變動成本法下存貨的單位成本$160", "全部成本法下存貨的單位成本$240；變動成本法下存貨的單位成本$195", "全部成本法下存貨的單位成本$320；變動成本法下存貨的單位成本$195"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00521', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '為使企業的整體利益達到最大，部門間轉撥價格應如何訂定？', '["變動成本", "付現成本", "付現成本＋機會成本", "固定製造成本＋機會成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00522', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '當公司有剩餘產能，且收到別家廠商的一次性特殊訂單。下列何種情況，可以接受報價低於 目前的產品售價？', '["接受訂單需要支付額外的固定成本", "當增額收入大於增額成本", "此特殊訂單會影響現有客戶的訂單", "當增額收入等於增額的營業利益時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00523', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '臺北公司產銷A、B兩種產品，A、B商品銷貨組合數量比率為4：1，各產品相關的單位售價 與單位變動成本資料如下： A產品 B產品 單位售價 $400 $200 單位變動成本 320 100 假設固定成本的總額為$340,000，所得稅率20%，若公司的目標利潤是稅後$400,000，則該公 司的A、B產品各項的銷貨量為何？', '["A產品8,000單位；B產品2,000單位", "A產品7,048單位；B產品1,762單位", "A產品22,286單位；B產品5,571單位", "A產品8,889單位；B產品1,111單位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00524', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '當一家公司的產品處在不完全競爭市場，會影響產品訂價決策的最主要因素為何？', '["顧客購買產品的意願", "公司可接受的最低售價", "替代性產品的製造程序", "競爭對手的成本結構"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00525', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司銷售一款暢銷型玩具，其產品單位成本為如下： 直接材料 $25 直接人工 14 變動製造費用 18 固定製造費用 13 總成本 $70 乙公司聯繫甲公司，願意協助製造生產該款9,200組的玩具，每組價格為$62。假如甲公司接受 乙公司的報價，將可以節省$48,000的固定製造費用。因此，甲公司應該決定自製或外購？兩 者方案之間所節省的成本為何？', '["自製，成本節省$25,600", "自製，成本節省$73,600", "外購，成本節省$2,000", "外購，成本節省$48,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00526', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司產銷A及B兩種產品，20X1年銷售的相關資訊如下： 靜態預算邊際貢獻總額 $144,000 A及B兩種產品預計銷售總量 ？（單位） A產品每單位預計邊際貢獻 $20 B產品每單位預計邊際貢獻 $60 銷售能量差異（sales-volumevariances） $8,000（不利） B產品預計銷售組合比率 40% A產品實際銷售組合比率 50% 20X1年的A及B兩種產品預計銷售總量，以及A產品的銷售組合差異為何？', '["預計銷售總量：4,000單位；A產品的銷售組合差異$6,800（不利）", "預計銷售總量：4,000單位；A產品的銷售組合差異$7,600（不利）", "預計銷售總量：4,000單位；A產品的銷售組合差異$0", "預計銷售總量：3,429單位；A產品的銷售組合差異$6,800（不利）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00527', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '寶景公司使用傳統成本會計制度，將品質控制成本平均分攤到所有產品，分攤率為直接人工 成本的20%。每個月主產品的直接人工成本為$40,000。為了能更公允地分攤品質控制成本， 寶景公司考慮採用作業基礎成本制（activity-based costing, ABC）。主產品每個月相關的資料 收集如下，主要有三項作業，分別是：⑴原物料檢驗、⑵製程檢驗、⑶產品認證。每項作業 係依其成本動因分攤成本。 作業 成本動因 主產品的作業量 原物料檢驗 材料種類數 $30/每種 40種 製程檢驗 產品單位數 $0.20/每單位 20,000單位 產品認證 訂單的數量 $90/每張 35張訂單 採用作業基礎成本制下，每個月主產品被分配到的品質成本為何？', '["$8,000", "每張訂單$150", "比傳統成本制度少$350", "比傳統成本制度多$350"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00528', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', 'OMG公司開發手機遊戲「群英打鬥」需投入8,000萬元的資金；預期獲益期間為4年（假設獲 益之現金為年底流入），必要報酬率為12%。每年所要求的最低淨現金流入需要多少，方可接 受此計畫？', '["2,000萬元", "2,457萬元", "2,634萬元", "2,798萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00529', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '文寶公司的營運總監收到公司部門甲的財務相關資訊。 部門甲 公司整體 銷貨收入 $45,000,000 $164,000,000 變動銷貨成本 23,000,000 78,000,000 變動銷管費用 12,000,000 29,000,000 固定成本與費用 12,000,000 30,000,000 營業淨利 （$2,000,000） $27,000,000 在看過上述資料後，營運總監對甲部門的績效感到非常失望，並考慮建議關閉甲部門。後來 與公司總裁討論過後，營運總監知道有一筆公司整體性的固定支出被分攤至甲部門，金額是 $5,000,000。在知道這項訊息後，營運總監是否應建議關閉甲部門，以及所持的理由為何？', '["不建議關閉甲部門，因為甲部門的可控制利潤（controllablemargin）為$3,000,000", "建議關閉甲部門，因為甲部門的可控制利潤為（$3,000,000）", "建議關閉甲部門，因為甲部門的可控制利潤為（$2,000,000）", "不建議關閉甲部門，因為甲部門的可控制利潤為$2,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00530', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '關於企業永續（corporatesustainability）發展的敘述，下列何者錯誤？', '["公司應選擇有善盡社會責任的供應商", "公司應縮短評估顧客信用評等的時間", "公司應公平對待其顧客", "公司應在製造程序中減少溫室氣體排放"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00531', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列何者是航空業採計平衡計分卡時，在顧客構面可採用的衡量指標？', '["乘客的抱怨次數下降10%", "乘客托運行李的等待時間不超過15分鐘", "超過90%的航班皆準點", "推出三種新口味的機內餐點，給乘客有選餐的方案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00532', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司六月份直接人工成本$36,000，此直接人工成本占主要成本60%，如果該月份的製造成 本是$85,000，則該月份的間接製造費用是多少？', '["$24,000", "$25,000", "$49,000", "$60,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00533', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司聘用50位專業清潔人工，其預算間接成本總共為1,050,000元，實際間接成本則為 793,800元；預計專業人工小時為500,000小時，實際人工小時則為504,000小時。若甲公司按人 工小時分攤間接成本，其預計間接成本分攤率為何？', '["每小時3.6元", "每小時3.5714元", "每小時2.1元", "每小時1.5元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00534', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司生產液晶電視，每一台電視機的售價為$190，公司在每個月的正常產能為10,000台，每 一台的生產成本如下： 直接材料………………………………………………$80 直接人工………………………………………………$40 製造費用（80%變動、20%固定） …………………$50 甲公司收到一張海外客戶的特別訂單，訂購量為2,000台。這筆訂單的銷管費用為每單位$12。 該公司目前每個月透過正常通路的銷售量為8,000台。這筆特別訂單的最低定價為多少元？', '["$190", "$182", "$172", "$170"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL);
